import { withDb } from "./db.mjs";

export async function ensureSchema(client) {
  await client.query(`
    CREATE TABLE IF NOT EXISTS accounts (
      account_id TEXT PRIMARY KEY,
      name TEXT NOT NULL,
      tier TEXT NOT NULL CHECK (tier IN ('strategic', 'midmarket', 'standard')),
      status TEXT NOT NULL CHECK (status IN ('active', 'at-risk', 'churned')),
      created_at DATE NOT NULL DEFAULT CURRENT_DATE
    )
  `);
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}

// Implement CRUD for the accounts resource against the live DB.
// Each function receives the pg client (with search_path set to the run schema) from src/db.mjs.
// Call ensureSchema(db) from src/schema.mjs before the first write.
import { ensureSchema } from "./schema.mjs";

function toDateString(value) {
  if (value == null) {
    return null;
  }

  if (value instanceof Date) {
    return value.toISOString().slice(0, 10);
  }

  if (typeof value === "string") {
    return value.slice(0, 10);
  }

  return new Date(value).toISOString().slice(0, 10);
}

function toAccount(row) {
  if (!row) {
    return null;
  }

  return {
    accountId: row.account_id,
    name: row.name,
    tier: row.tier,
    status: row.status,
    createdAt: toDateString(row.created_at),
  };
}

// Create a accounts record. Return the created document.
export async function createAccounts(db, data) {
  await ensureSchema(db);

  const result = await db.query(
    `
      INSERT INTO accounts (account_id, name, tier, status, created_at)
      VALUES ($1, $2, $3, $4, COALESCE($5::date, CURRENT_DATE))
      RETURNING *
    `,
    [data.accountId, data.name, data.tier, data.status, toDateString(data.createdAt)]
  );

  return toAccount(result.rows[0]);
}

// Read a accounts by its id. Return the document or null.
export async function getAccounts(db, id) {
  const result = await db.query("SELECT * FROM accounts WHERE account_id = $1", [id]);
  return toAccount(result.rows[0]);
}

// Update a accounts by id with partial data. Return the updated document.
export async function updateAccounts(db, id, data) {
  await ensureSchema(db);

  const result = await db.query(
    `
      UPDATE accounts
      SET
        name = COALESCE($2, name),
        tier = COALESCE($3, tier),
        status = COALESCE($4, status),
        created_at = COALESCE($5::date, created_at)
      WHERE account_id = $1
      RETURNING *
    `,
    [id, data.name ?? null, data.tier ?? null, data.status ?? null, toDateString(data.createdAt)]
  );

  return toAccount(result.rows[0]);
}

// Delete a accounts by id. Return true if deleted.
export async function deleteAccounts(db, id) {
  await ensureSchema(db);

  const result = await db.query("DELETE FROM accounts WHERE account_id = $1", [id]);
  return result.rowCount > 0;
}

